// Function to set a cookie
function setCookie(name, value, days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    const expires = "expires=" + date.toUTCString();
    document.cookie = name + "=" + value + ";" + expires + ";path=/";
}

// Function to get a cookie
function getCookie(name) {
    const nameEQ = name + "=";
    const ca = document.cookie.split(';');
    for (let i = 0; i < ca.length; i++) {
        let c = ca[i];
        while (c.charAt(0) === ' ') c = c.substring(1, c.length);
        if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
    }
    return null;
}

// Function to hash a password
function hashPassword(password) {
    // Simple hashing for demonstration purposes
    let hash = 0, i, chr;
    if (password.length === 0) return hash;
    for (i = 0; i < password.length; i++) {
        chr   = password.charCodeAt(i);
        hash  = ((hash << 5) - hash) + chr;
        hash |= 0; // Convert to 32bit integer
    }
    return hash;
}

// Function to handle login with 'Remember Me'
function login(username, password, rememberMe) {
    const hashedPassword = hashPassword(password);
    if (rememberMe) {
        setCookie('username', username, 30);
        setCookie('passwordHash', hashedPassword, 30);
    }
    // Proceed with actual login logic
    authenticateUser(username, hashedPassword);
}

// Function to auto-login on page load
